### Step 4: MCP HTTP Handler

File: `/Users/marcus/conductor/workspaces/brain/minnetonka-v1/app/src/server/mcp/mcp-route.ts`

Add import for `ObservationType`, `OBSERVATION_TYPES` from contracts, and for `createObservation` from observation/queries.

Add a new handler inside `createMcpRouteHandlers()`, in the Tier 3 Write section (after `handleLogNote`, around line 622):

```typescript
/** POST /api/mcp/:workspaceId/observations — Log an observation */
async function handleLogObservation(workspaceId: string, request: Request): Promise<Response> {
  const auth = await requireAuth(request, workspaceId);
  if (auth instanceof Response) return auth;

  const body = await parseJsonBody<{
    text: string;
    category: string;  // maps to observation_type
    severity: string;
    target?: string;    // entity_id in table:id format
    files?: string[];
    code_snippet?: string;
    session_id?: string;
    context?: { project?: string; feature?: string; task?: string };
  }>(request);
  if (body instanceof Response) return body;
  if (!body.text) return jsonError("text is required", 400);
  if (!body.category) return jsonError("category is required", 400);
  if (!body.severity) return jsonError("severity is required", 400);

  // Validate category is a valid ObservationType
  if (!OBSERVATION_TYPES.includes(body.category as ObservationType)) {
    return jsonError(`invalid category: must be one of ${OBSERVATION_TYPES.join(", ")}`, 400);
  }

  // Validate severity
  if (!["info", "warning", "conflict"].includes(body.severity)) {
    return jsonError("invalid severity: must be info, warning, or conflict", 400);
  }

  // Resolve target entity if provided
  let relatedRecord: RecordId<"project" | "feature" | "task" | "decision" | "question", string> | undefined;
  if (body.target) {
    try {
      relatedRecord = parseRecordIdString(body.target, ["project", "feature", "task", "decision", "question"]) as RecordId<"project" | "feature" | "task" | "decision" | "question", string>;
    } catch {
      return jsonError(`invalid target entity: ${body.target}`, 400);
    }
  }

  // Generate embedding
  const embedding = await createEmbeddingVector(
    deps.embeddingModel,
    body.text,
    config.embeddingDimension,
  );
  if (!embedding) {
    return jsonError("failed to create embedding for observation", 500);
  }

  // Resolve session record if provided
  const sourceSessionRecord = body.session_id
    ? new RecordId("agent_session", body.session_id)
    : undefined;

  const now = new Date();

  const observationRecord = await createObservation({
    surreal,
    workspaceRecord: auth.workspaceRecord,
    text: body.text,
    severity: body.severity as ObservationSeverity,
    observationType: body.category as ObservationType,
    sourceAgent: "code-agent",
    now,
    ...(sourceSessionRecord ? { sourceSessionRecord } : {}),
    ...(relatedRecord ? { relatedRecord } : {}),
    embedding,
    ...(body.files?.length ? { files: body.files } : {}),
    ...(body.code_snippet ? { codeSnippet: body.code_snippet } : {}),
  });

  // Create observed_in edge: observation -> agent_session
  if (sourceSessionRecord) {
    await surreal
      .relate(
        observationRecord,
        new RecordId("observed_in", randomUUID()),
        sourceSessionRecord,
        { added_at: now },
      )
      .output("after");
  }

  logInfo("mcp.observation.created", "Observation logged via MCP", {
    workspaceId,
    observationId: observationRecord.id as string,
    observationType: body.category,
    severity: body.severity,
  });

  return jsonResponse({
    observation_id: `observation:${observationRecord.id as string}`,
    severity: body.severity,
    status: "open",
  }, 201);
}
```

Add `handleLogObservation` to the return object (line 826), add `randomUUID` import from `node:crypto`, and add the missing imports (`createObservation`, `createEmbeddingVector`, `ObservationType`, `OBSERVATION_TYPES`, `ObservationSeverity`).

