### Step 6: CLI HTTP Client Method

File: `/Users/marcus/conductor/workspaces/brain/minnetonka-v1/cli/http-client.ts`

Add method after `logImplementationNote()` (around line 155):

```typescript
async logObservation(body: {
  text: string;
  category: string;
  severity: string;
  target?: string;
  files?: string[];
  code_snippet?: string;
  session_id?: string;
  context?: { project?: string; feature?: string; task?: string };
}): Promise<unknown> {
  const res = await fetch(this.url("/observations"), {
    method: "POST",
    headers: this.headers(),
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(`Failed to log observation: ${res.status} ${await res.text()}`);
  return res.json();
}
```

