server.tool(
  "log_observation",
  "Log a codebase observation to the knowledge graph. Use when you notice contradictions between code and documented decisions, duplicated logic, missing implementations, deprecated patterns, recurring code patterns, or anomalies. Creates an observation entity with optional links to the entity it concerns and the current agent session.",
  {
    text: z.string().describe("What you observed, with enough context for a human to act on it"),
    category: z
      .enum(["contradiction", "duplication", "missing", "deprecated", "pattern", "anomaly"])
