        "contradiction: code contradicts a decision/spec. duplication: duplicated logic found. missing: expected implementation absent. deprecated: outdated pattern in use. pattern: recurring code pattern worth codifying. anomaly: something unexpected.",
      ),
    severity: z
      .enum(["info", "warning", "conflict"])
      .describe(
        "info: awareness-level signal. warning: risk that should be addressed soon. conflict: contradiction needing human resolution.",
      ),
    target: z.string().optional().describe("Entity ID this observation concerns, in table:id format (e.g. task:abc123, decision:def456)"),
    files: z.array(z.string()).optional().describe("File paths relevant to the observation"),
    code_snippet: z.string().optional().describe("Short code excerpt providing context (keep under 500 chars)"),
    session_id: z.string().optional().describe("Current agent session ID to link this observation to"),
  },
  async (input) => {
    const result = await client.logObservation(input);
    return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
