  2→import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
  3→import { z } from "zod";
  4→import { requireConfig } from "./config";
  5→import { BrainHttpClient } from "./http-client";
  6→
  7→export async function runMcpServer(): Promise<void> {
  8→  const config = requireConfig();
  9→  const client = new BrainHttpClient(config);
 10→
 11→  const server = new McpServer({
 12→    name: "brain",
 13→    version: "0.1.0",
 14→  });
 15→
 16→  // =========================================================================
 17→  // Tier 1 — Read Tools
 18→  // =========================================================================
 19→
 20→  server.tool(
 21→    "get_project_context",
 22→    "Get token-budgeted context packet for a project. Returns decisions, tasks, constraints, open questions, and recent changes. Use at session start or to refresh context mid-session.",
 23→    {
 24→      project_id: z.string().describe("Project ID"),
 25→      task_id: z.string().optional().describe("Task ID for task-scoped context (focused on one task's subgraph)"),
 26→      since: z.string().optional().describe("ISO timestamp to get changes since (e.g. last session end)"),
 27→    },
 28→    async (input) => {
 29→      const result = await client.getContext(input);
 30→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 31→    },
 32→  );
 33→
 34→  server.tool(
 35→    "get_active_decisions",
 36→    "Get active decisions for a project, grouped by status (confirmed, provisional, contested). Optionally filter by area/category.",
 37→    {
 38→      project_id: z.string().describe("Project ID"),
 39→      area: z.string().optional().describe("Category filter: engineering, research, marketing, operations, design, sales"),
 40→    },
 41→    async (input) => {
 42→      const result = await client.getDecisions(input);
 43→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
 44→    },
 45→  );
 46→
 47→  server.tool(
 48→    "get_task_dependencies",
 49→    "Get full dependency tree for a task: what it depends on, what depends on it, and its subtasks.",
 50→    {
 51→      task_id: z.string().describe("Task ID"),
