 52→export async function acknowledgeObservation(input: {
 53→  surreal: Surreal;
 54→  workspaceRecord: RecordId<"workspace", string>;
 55→  observationRecord: ObservationRecord;
 56→  now: Date;
 57→}): Promise<void> {
 58→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 59→  if (!row) {
 60→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 61→  }
 62→
 63→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 64→    throw new Error("observation is outside the current workspace scope");
 65→  }
 66→
 67→  await input.surreal.update(input.observationRecord).merge({
 68→    status: "acknowledged" satisfies ObservationStatus,
 69→    updated_at: input.now,
 70→  });
 71→}
 72→
 73→export async function resolveObservation(input: {
 74→  surreal: Surreal;
 75→  workspaceRecord: RecordId<"workspace", string>;
 76→  observationRecord: ObservationRecord;
 77→  now: Date;
 78→  resolvedByRecord?: RecordId<"person", string>;
 79→}): Promise<void> {
 80→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 81→  if (!row) {
 82→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 83→  }
 84→
 85→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 86→    throw new Error("observation is outside the current workspace scope");
 87→  }
 88→
 89→  await input.surreal.update(input.observationRecord).merge({
 90→    status: "resolved" satisfies ObservationStatus,
 91→    resolved_at: input.now,
 92→    ...(input.resolvedByRecord ? { resolved_by: input.resolvedByRecord } : {}),
 93→    updated_at: input.now,
 94→  });
 95→}
