223→/** Build task-scoped context: subtasks, parent feature, siblings, dependencies, related sessions */
224→async function buildTaskScope(
225→  surreal: Surreal,
226→  _workspaceRecord: RecordId<"workspace", string>,
227→  _projectRecord: RecordId<"project", string>,
228→  taskId: string,
229→): Promise<TaskScopeContext> {
230→  const taskRecord = new RecordId("task", taskId);
231→  const task = await surreal.select<TaskRow>(taskRecord);
232→  if (!task) {
233→    throw new Error(`task not found: ${taskId}`);
234→  }
235→
236→  // Load subtasks, parent feature, dependencies, and related sessions in parallel
237→  const taskScopeQuery = `
238→    -- Subtasks of this task
239→    SELECT id, title, status
240→    FROM task
241→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
242→    ORDER BY created_at ASC;
243→
244→    -- Parent feature (via has_task edge)
245→    SELECT id, name, description
246→    FROM feature
247→    WHERE id IN (SELECT VALUE \`in\` FROM has_task WHERE out = $task)
248→    LIMIT 1;
249→
250→    -- Dependencies (tasks this task depends on)
251→    SELECT id, title, status
252→    FROM task
253→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
254→
255→    -- Recent agent sessions that touched this task
256→    SELECT id, agent, ended_at, summary
257→    FROM agent_session
258→    WHERE task_id = $task AND ended_at != NONE
259→    ORDER BY ended_at DESC LIMIT 5;
260→  `;
261→
262→  const results = await surreal
263→    .query<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>(taskScopeQuery, {
264→      task: taskRecord,
265→    })
266→    .collect<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>();
267→
268→  const [subtaskRows, featureRows, dependencyRows, sessionRows] = results;
269→
270→  const parentFeature = featureRows.length > 0
271→    ? {
272→        id: toId(featureRows[0].id),
273→        name: featureRows[0].name,
274→        ...(featureRows[0].description ? { description: featureRows[0].description } : {}),
275→      }
276→    : undefined;
277→
278→  // Load sibling tasks (other tasks under same feature)
279→  let siblingTasks: { id: string; title: string; status: string }[] = [];
280→  if (parentFeature && featureRows.length > 0) {
281→    const [siblingRows] = await surreal
282→      .query<[TaskRow[]]>(
283→        `SELECT id, title, status FROM task
284→         WHERE id IN (SELECT VALUE out FROM has_task WHERE \`in\` = $feature)
285→           AND id != $task
286→         ORDER BY created_at ASC LIMIT 20;`,
287→        { feature: featureRows[0].id, task: taskRecord },
288→      )
289→      .collect<[TaskRow[]]>();
290→
291→    siblingTasks = siblingRows.map((t) => ({
292→      id: toId(t.id),
293→      title: t.title,
294→      status: t.status,
295→    }));
296→  }
297→
298→  return {
299→    task: {
300→      id: toId(task.id),
301→      title: task.title,
302→      ...(task.description ? { description: task.description } : {}),
303→      status: task.status,
304→      ...(task.category ? { category: task.category } : {}),
305→    },
306→    subtasks: subtaskRows.map((s) => ({
307→      id: toId(s.id),
308→      title: s.title,
309→      status: s.status,
310→    })),
311→    parent_feature: parentFeature,
312→    sibling_tasks: siblingTasks,
313→    dependencies: dependencyRows.map((d) => ({
314→      id: toId(d.id),
315→      title: d.title,
316→      status: d.status,
317→    })),
318→    related_sessions: sessionRows.map((s) => ({
319→      id: toId(s.id),
320→      agent: s.agent,
321→      ended_at: toIso(s.ended_at),
