117→  /** GET /api/mcp/:workspaceId/projects — List workspace projects */
118→  async function handleListProjects(workspaceId: string): Promise<Response> {
119→    const result = await resolveWorkspaceById(workspaceId);
120→    if (result instanceof Response) return result;
121→
122→    const [projectRows] = await surreal
123→      .query<[ProjectRow[]]>(
124→        "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
125→        { workspace: result.workspaceRecord },
126→      )
127→      .collect<[ProjectRow[]]>();
128→
129→    return jsonResponse({
130→      workspace: { id: workspaceId, name: result.workspace.name },
131→      projects: projectRows.map((p) => ({ id: p.id.id as string, name: p.name })),
132→    }, 200);
