279→  /** POST /api/mcp/:workspaceId/decisions/resolve — Infer decision from graph */
280→  async function handleResolveDecision(workspaceId: string, request: Request): Promise<Response> {
281→    const auth = await requireAuth(request, workspaceId);
282→    if (auth instanceof Response) return auth;
283→
284→    const body = await parseJsonBody<{
285→      question: string;
286→      options?: string[];
287→      context?: { project?: string; feature?: string };
288→    }>(request);
289→    if (body instanceof Response) return body;
290→    if (!body.question) return jsonError("question is required", 400);
291→
292→    // Embed the question and search for related decisions
293→    const queryEmbedding = await createEmbeddingVector(
294→      deps.embeddingModel,
295→      body.question,
296→      config.embeddingDimension,
297→    );
298→
299→    if (!queryEmbedding) {
300→      return jsonResponse({
301→        decision: undefined,
302→        confidence: 0,
303→        status: "unresolved",
304→        rationale: "Could not create embedding for question",
305→        sources: [],
306→      }, 200);
307→    }
308→
309→    const projectRecord = body.context?.project
310→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
311→      : undefined;
312→
313→    const candidates = await searchEntitiesByEmbedding({
314→      surreal,
315→      workspaceRecord: auth.workspaceRecord,
316→      queryEmbedding,
317→      kinds: ["decision"],
318→      ...(projectRecord ? { projectRecord } : {}),
319→      limit: 10,
320→    });
321→
322→    // Check if any existing decision resolves the question
323→    const questionTokens = normalizeTokens(body.question);
324→    const relevant = candidates.filter((c) => {
325→      const tokens = normalizeTokens(c.name);
326→      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
327→    });
328→
329→    if (relevant.length > 0) {
330→      const best = relevant[0];
331→      return jsonResponse({
332→        decision: best.name,
333→        confidence: Number(best.score.toFixed(4)),
334→        status: best.status ?? "unknown",
335→        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
336→        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
337→      }, 200);
338→    }
339→
340→    return jsonResponse({
341→      decision: undefined,
342→      confidence: 0,
343→      status: "unresolved",
344→      rationale: "No existing decision found that resolves this question",
345→      sources: candidates.slice(0, 5).map((c) => ({
346→        id: `${c.kind}:${c.id}`,
347→        name: c.name,
348→        score: Number(c.score.toFixed(4)),
349→      })),
350→    }, 200);
351→  }
