353→  /** POST /api/mcp/:workspaceId/constraints/check — Check proposed action */
354→  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
355→    const auth = await requireAuth(request, workspaceId);
356→    if (auth instanceof Response) return auth;
357→
358→    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
359→    if (body instanceof Response) return body;
360→    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
361→
362→    const queryEmbedding = await createEmbeddingVector(
363→      deps.embeddingModel,
364→      body.proposed_action,
365→      config.embeddingDimension,
366→    );
367→
368→    if (!queryEmbedding) {
369→      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
370→    }
371→
372→    const projectRecord = body.project
373→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
374→      : undefined;
375→
376→    const candidates = await listDecisionConstraintCandidates({
377→      surreal,
378→      workspaceRecord: auth.workspaceRecord,
379→      queryEmbedding,
380→      ...(projectRecord ? { projectRecord } : {}),
381→      limit: 14,
382→    });
383→
384→    const actionTokens = normalizeTokens(body.proposed_action);
385→    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
386→    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
387→    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
388→
389→    for (const candidate of candidates) {
390→      const candidateTokens = normalizeTokens(candidate.name);
391→      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
392→      const status = candidate.status?.toLowerCase();
393→
394→      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
395→        hardConflicts.push({
396→          id: `${candidate.kind}:${candidate.id}`,
397→          name: candidate.name,
398→          score: Number(candidate.score.toFixed(4)),
399→          reason: `Decision is marked ${status}.`,
400→        });
401→        continue;
402→      }
403→
404→      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
405→        supporting.push({
406→          id: `${candidate.kind}:${candidate.id}`,
407→          name: candidate.name,
408→          score: Number(candidate.score.toFixed(4)),
409→          reason: "High-similarity decision aligns with proposed action.",
410→        });
411→        continue;
412→      }
413→
414→      if (candidate.score >= 0.72) {
415→        softTensions.push({
416→          id: `${candidate.kind}:${candidate.id}`,
417→          name: candidate.name,
418→          score: Number(candidate.score.toFixed(4)),
419→          reason: overlap
420→            ? "Related decision/question may require consistency checks."
421→            : "Semantically related context may be affected.",
422→        });
423→      }
424→    }
425→
426→    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
427→  }
