364→/** Update task status with subtask rollup */
365→export async function updateTaskStatus(input: {
366→  surreal: Surreal;
367→  taskRecord: RecordId<"task", string>;
368→  status: string;
369→  notes?: string;
370→}): Promise<{ task_id: string; status: string; parent_status?: string }> {
371→  const now = new Date();
372→
373→  await input.surreal.update(input.taskRecord).merge({
374→    status: input.status,
375→    updated_at: now,
376→  });
377→
378→  if (input.notes) {
379→    // Append note to description_entries
380→    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
381→    const entries = task?.description_entries ?? [];
382→    entries.push({ text: input.notes, created_at: now });
383→    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
384→  }
385→
386→  // Check if this task has a parent (subtask_of) and compute rollup
387→  const [parentRows] = await input.surreal
388→    .query<[Array<{ out: RecordId<"task", string> }>]>(
389→      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
390→      { task: input.taskRecord },
391→    )
392→    .collect<[Array<{ out: RecordId<"task", string> }>]>();
393→
394→  let parentStatus: string | undefined;
395→
396→  if (parentRows.length > 0) {
397→    const parentRecord = parentRows[0].out;
398→    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
399→  }
400→
401→  return {
402→    task_id: toId(input.taskRecord),
403→    status: input.status,
404→    ...(parentStatus ? { parent_status: parentStatus } : {}),
405→  };
406→}
