 50→async function parseJsonBody<T>(request: Request): Promise<T | Response> {
 51→  try {
 52→    return (await request.json()) as T;
 53→  } catch {
 54→    return jsonError("invalid JSON body", 400);
 55→  }
 56→}
 57→
 58→const ENTITY_TABLES: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"];
 59→
 60→function normalizeTokens(value: string): Set<string> {
 61→  return new Set(
 62→    value
 63→      .toLowerCase()
 64→      .replace(/[^a-z0-9\s]/g, " ")
 65→      .split(/\s+/)
 66→      .map((t) => t.trim())
 67→      .filter((t) => t.length > 2),
 68→  );
 69→}
 70→
 71→function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
 72→  for (const v of a) {
 73→    if (b.has(v)) return true;
 74→  }
 75→  return false;
 76→}
