499→    const featureRecord = body.context?.feature
500→      ? await resolveWorkspaceFeatureRecord({ surreal, workspaceRecord: auth.workspaceRecord, featureInput: body.context.feature })
501→      : undefined;
502→
503→    const questionRecord = await createQuestionRecord({
504→      surreal,
505→      text: body.text,
506→      status: "asked",
507→      now: new Date(),
508→      workspaceRecord: auth.workspaceRecord,
509→      ...(projectRecord ? { projectRecord } : {}),
510→      ...(featureRecord ? { featureRecord } : {}),
511→    });
512→
513→    // Set coding agent fields directly
514→    const now = new Date();
515→    await surreal.update(questionRecord).merge({
516→      asked_by: "code-agent",
517→      ...(body.options?.length ? { options: body.options } : {}),
518→      ...(body.blocking_task ? { blocking_task: new RecordId("task", body.blocking_task) } : {}),
519→    });
520→
521→    // If blocking_task, create a blocks edge (question blocks task)
522→    if (body.blocking_task) {
523→      const taskRecord = new RecordId("task", body.blocking_task);
524→      await surreal
525→        .relate(questionRecord, new RecordId("depends_on", crypto.randomUUID()), taskRecord, {
526→          type: "blocks",
527→          added_at: now,
528→        })
529→        .output("after");
530→    }
531→
532→    logInfo("mcp.question.created", "Question created via MCP", {
533→      workspaceId,
534→      questionId: questionRecord.id as string,
535→    });
536→
537→    return jsonResponse({
538→      question_id: `question:${questionRecord.id as string}`,
539→      status: "asked",
540→    }, 201);
