 52→function toId(record: RecordId<string, string>): string {
 53→  return `${record.table.name}:${record.id as string}`;
 54→}
 55→
 56→function toIso(value: Date | string | undefined): string {
 57→  if (!value) return "";
 58→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
