 88→/** Build a broad project context packet (all decisions, tasks, questions for a project) */
 89→export async function buildProjectContext(input: {
 90→  surreal: Surreal;
 91→  workspaceRecord: RecordId<"workspace", string>;
 92→  workspaceName: string;
 93→  projectRecord: RecordId<"project", string>;
 94→  taskId?: string;
 95→  since?: string;
 96→}): Promise<ContextPacket> {
 97→  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
 98→
 99→  // Load project details
100→  const project = await surreal.select<ProjectRow>(projectRecord);
101→  if (!project) {
102→    throw new Error(`project not found: ${projectRecord.id}`);
103→  }
104→
105→  // Load project-scoped entities in parallel
106→  const projectEntitiesQuery = `
107→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
108→
109→    SELECT id, summary, status, rationale, decided_at, category, priority
110→    FROM decision
111→    WHERE workspace = $workspace AND id IN $project_entity_ids
112→    ORDER BY created_at DESC LIMIT 50;
113→
114→    SELECT id, title, status, priority, category, description
115→    FROM task
116→    WHERE workspace = $workspace AND id IN $project_entity_ids
117→    ORDER BY created_at DESC LIMIT 50;
118→
119→    SELECT id, text, status, context, priority
120→    FROM question
121→    WHERE workspace = $workspace AND id IN $project_entity_ids
122→    ORDER BY created_at DESC LIMIT 30;
123→
124→    SELECT id, text, severity, status, category
125→    FROM observation
126→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
127→    ORDER BY created_at DESC LIMIT 20;
128→  `;
129→
130→  const results = await surreal
131→    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
132→      project: projectRecord,
133→      workspace: workspaceRecord,
134→    })
135→    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
136→
137→  const [, decisionRows, taskRows, questionRows, observationRows] = results;
138→
139→  // Categorize decisions by status
140→  const confirmed: DecisionContext[] = [];
141→  const provisional: DecisionContext[] = [];
142→  const contested: DecisionContext[] = [];
143→
144→  for (const d of decisionRows) {
145→    const ctx: DecisionContext = {
146→      id: toId(d.id),
147→      summary: d.summary,
148→      status: d.status,
149→      ...(d.rationale ? { rationale: d.rationale } : {}),
150→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
151→      ...(d.category ? { category: d.category } : {}),
152→      ...(d.priority ? { priority: d.priority } : {}),
153→    };
154→
155→    if (d.status === "contested") {
156→      contested.push(ctx);
157→    } else if (d.status === "provisional" || d.status === "inferred") {
158→      provisional.push(ctx);
159→    } else if (d.status === "confirmed") {
160→      confirmed.push(ctx);
161→    }
162→  }
163→
164→  // Map tasks
165→  const activeTasks: TaskContext[] = taskRows
166→    .filter((t) => t.status !== "done" && t.status !== "completed")
167→    .map((t) => ({
168→      id: toId(t.id),
169→      title: t.title,
170→      status: t.status,
171→      ...(t.priority ? { priority: t.priority } : {}),
172→      ...(t.category ? { category: t.category } : {}),
173→    }));
174→
175→  // Map questions
176→  const openQuestions: QuestionContext[] = questionRows
177→    .filter((q) => q.status !== "answered" && q.status !== "resolved")
178→    .map((q) => ({
179→      id: toId(q.id),
180→      text: q.text,
181→      status: q.status,
182→      ...(q.context ? { context: q.context } : {}),
183→      ...(q.priority ? { priority: q.priority } : {}),
184→    }));
185→
186→  // Map observations
187→  const observations: ObservationContext[] = observationRows.map((o) => ({
188→    id: toId(o.id),
189→    text: o.text,
190→    severity: o.severity,
191→    status: o.status,
192→    ...(o.category ? { category: o.category } : {}),
193→  }));
194→
195→  // Build recent changes if `since` provided
196→  const recentChanges: RecentChangeContext[] = input.since
197→    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
198→    : [];
199→
200→  // Build task scope if taskId provided

200→
201→  const results = await input.surreal
202→    .query<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
203→      query,
204→      {
205→        workspace: input.workspaceRecord,
206→        project: input.projectRecord,
207→        ...(input.area ? { area: input.area } : {}),
208→      },
209→    )
210→    .collect<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
211→
212→  const [, decisionRows, observationRows] = results;
213→
214→  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
215→
216→  for (const d of decisionRows) {
217→    constraints.push({
218→      text: d.text,
219→      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
220→      severity: d.status === "contested" ? "hard" : "hard",
221→    });
222→  }
223→
224→  for (const o of observationRows) {
225→    constraints.push({
226→      text: o.text,
227→      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
228→      severity: o.severity === "conflict" ? "hard" : "soft",
229→    });
230→  }
231→
232→  return constraints;
233→}
