235→/** List recent changes since a timestamp */
236→export async function listRecentChanges(input: {
237→  surreal: Surreal;
238→  workspaceRecord: RecordId<"workspace", string>;
239→  projectRecord?: RecordId<"project", string>;
240→  since: string;
241→}): Promise<Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>> {
242→  const sinceDate = new Date(input.since);
243→
244→  const projectFilter = input.projectRecord
245→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
246→    : "";
247→
248→  const query = `
249→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
250→    FROM decision
251→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
252→    ORDER BY updated_at DESC LIMIT 20;
253→
254→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
255→    FROM task
256→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
257→    ORDER BY updated_at DESC LIMIT 20;
258→
259→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
260→    FROM question
261→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
262→    ORDER BY updated_at DESC LIMIT 20;
263→
264→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
265→  `;
266→
267→  const results = await input.surreal
268→    .query<[null, null, null, EntityChangeRow[]]>(query, {
269→      workspace: input.workspaceRecord,
270→      since: sinceDate,
271→      ...(input.projectRecord ? { project: input.projectRecord } : {}),
272→    })
273→    .collect<[null, null, null, EntityChangeRow[]]>();
274→
275→  return (results[3] ?? []).map((r) => ({
276→    entity_type: r.entity_type,
277→    entity_name: r.entity_name,
278→    change_type: r.change_type,
279→    changed_at: toIso(r.changed_at),
280→  }));
281→}
