 82→export function createMcpRouteHandlers(deps: ServerDependencies) {
 83→  const { surreal, config, extractionModel } = deps;
 84→
 85→  // ---- Auth helper: returns McpAuthResult or error Response ----
 86→  async function requireAuth(request: Request, workspaceId: string): Promise<McpAuthResult | Response> {
 87→    return authenticateMcpRequest(request, workspaceId, surreal);
 88→  }
