 90→  // ---- Workspace helper (no auth - for legacy/unauthenticated routes) ----
 91→  async function resolveWorkspaceById(workspaceId: string): Promise<{ workspaceRecord: RecordId<"workspace", string>; workspace: WorkspaceRow } | Response> {
 92→    const workspaceRecord = new RecordId("workspace", workspaceId);
 93→    const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
 94→    if (!workspace) return jsonError("workspace not found", 404);
 95→    return { workspaceRecord, workspace };
 96→  }
