 98→  // =========================================================================
 99→  // Setup
100→  // =========================================================================
101→
102→  /** POST /api/mcp/:workspaceId/auth/init — Generate API key */
103→  async function handleAuthInit(workspaceId: string): Promise<Response> {
104→    const result = await resolveWorkspaceById(workspaceId);
105→    if (result instanceof Response) return result;
106→
107→    const apiKey = generateApiKey();
108→    const hash = await hashApiKey(apiKey);
109→
110→    await surreal.update(result.workspaceRecord).merge({ api_key_hash: hash, updated_at: new Date() });
111→
112→    logInfo("mcp.auth.init", "API key generated for workspace", { workspaceId });
113→
114→    return jsonResponse({ api_key: apiKey, workspace: { id: workspaceId, name: result.workspace.name } }, 200);
115→  }
