139→  /** POST /api/mcp/:workspaceId/context — Get project context (broad or task-scoped) */
140→  async function handleGetContext(workspaceId: string, request: Request): Promise<Response> {
141→    const auth = await requireAuth(request, workspaceId);
142→    if (auth instanceof Response) return auth;
143→
144→    const body = await parseJsonBody<{ project_id: string; task_id?: string; since?: string }>(request);
145→    if (body instanceof Response) return body;
146→    if (!body.project_id) return jsonError("project_id is required", 400);
147→
148→    const projectRecord = new RecordId("project", body.project_id);
149→    const project = await surreal.select<ProjectRow>(projectRecord);
150→    if (!project) return jsonError("project not found", 404);
151→
152→    try {
153→      const contextPacket = await buildProjectContext({
154→        surreal,
155→        workspaceRecord: auth.workspaceRecord,
156→        workspaceName: auth.workspaceName,
157→        projectRecord,
158→        taskId: body.task_id,
159→        since: body.since,
160→      });
161→
162→      logInfo("mcp.context.built", "MCP context packet assembled", {
163→        workspaceId,
164→        projectId: body.project_id,
165→        taskId: body.task_id,
166→        decisionsCount:
