168→          contextPacket.decisions.provisional.length +
169→          contextPacket.decisions.contested.length,
170→        tasksCount: contextPacket.active_tasks.length,
171→      });
172→
173→      return jsonResponse(contextPacket, 200);
174→    } catch (error) {
175→      logError("mcp.context.failed", "Failed to build MCP context", error);
