199→      parent_task_id: z.string().describe("Parent task ID to add subtask under"),
200→      title: z.string().describe("Subtask title"),
201→      category: z.string().optional().describe("Category (inherits from parent if not specified)"),
202→      rationale: z.string().optional().describe("Why this subtask is needed"),
203→    },
204→    async (input) => {
205→      const result = await client.createSubtask(input);
206→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
207→    },
208→  );
209→
210→  server.tool(
211→    "log_implementation_note",
212→    "Append an implementation note to any entity (decision, task, feature). Use to record what was implemented and how.",
213→    {
214→      entity_id: z.string().describe("Entity ID in table:id format (e.g. decision:abc123)"),
215→      note: z.string().describe("What was implemented and how"),
216→      files_changed: z.array(z.string()).optional().describe("Paths of files touched"),
217→    },
218→    async (input) => {
219→      const result = await client.logImplementationNote(input);
220→      return { content: [{ type: "text" as const, text: JSON.stringify(result, undefined, 2) }] };
221→    },
222→  );
223→
224→  // =========================================================================
225→  // Connect via stdio
226→  // =========================================================================
227→
228→  const transport = new StdioServerTransport();
229→  await server.connect(transport);
230→}
