169→/** List architecture constraints for a project */
170→export async function listProjectConstraints(input: {
171→  surreal: Surreal;
172→  workspaceRecord: RecordId<"workspace", string>;
173→  projectRecord: RecordId<"project", string>;
174→  area?: string;
175→}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
176→  // Constraints come from two sources:
177→  // 1. Decisions marked as confirmed/contested (hard constraints)
178→  // 2. Observations with severity "conflict" or "warning"
179→
180→  const areaFilter = input.area ? `AND category = $area` : "";
181→
182→  const query = `
183→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
184→
185→    SELECT summary AS text, "decision" AS source_type, status, id
186→    FROM decision
187→    WHERE workspace = $workspace
188→      AND id IN $project_entity_ids
189→      AND status IN ["confirmed", "contested"]
190→      ${areaFilter}
191→    ORDER BY created_at DESC LIMIT 30;
192→
193→    SELECT text, "observation" AS source_type, severity, id
194→    FROM observation
195→    WHERE workspace = $workspace
196→      AND status IN ["open", "acknowledged"]
197→      AND severity IN ["conflict", "warning"]
198→    ORDER BY created_at DESC LIMIT 20;
199→  `;
200→
201→  const results = await input.surreal
202→    .query<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
203→      query,
204→      {
205→        workspace: input.workspaceRecord,
206→        project: input.projectRecord,
207→        ...(input.area ? { area: input.area } : {}),
208→      },
209→    )
210→    .collect<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
211→
212→  const [, decisionRows, observationRows] = results;
213→
214→  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
215→
216→  for (const d of decisionRows) {
217→    constraints.push({
218→      text: d.text,
219→      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
220→      severity: d.status === "contested" ? "hard" : "hard",
221→    });
222→  }
223→
224→  for (const o of observationRows) {
225→    constraints.push({
226→      text: o.text,
227→      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
228→      severity: o.severity === "conflict" ? "hard" : "soft",
229→    });
230→  }
231→
232→  return constraints;
233→}
