742→  /** POST /api/mcp/:workspaceId/commits/check — Pre-commit LLM analysis */
743→  async function handleCheckCommit(workspaceId: string, request: Request): Promise<Response> {
744→    const auth = await requireAuth(request, workspaceId);
745→    if (auth instanceof Response) return auth;
746→
747→    const body = await parseJsonBody<{
748→      project_id: string;
749→      diff: string;
750→      commit_message: string;
751→    }>(request);
752→    if (body instanceof Response) return body;
753→    if (!body.project_id) return jsonError("project_id is required", 400);
754→    if (!body.diff) return jsonError("diff is required", 400);
755→
756→    const projectRecord = new RecordId("project", body.project_id);
757→
758→    // Load project context for analysis
759→    const [decisions, constraints, activeTasks] = await Promise.all([
760→      listProjectDecisions({
761→        surreal,
762→        workspaceRecord: auth.workspaceRecord,
763→        projectRecord,
764→      }),
765→      listProjectConstraints({
766→        surreal,
767→        workspaceRecord: auth.workspaceRecord,
768→        projectRecord,
769→      }),
770→      surreal.query<[Array<{ title: string; status: string }>]>(
771→        `SELECT title, status FROM task WHERE workspace = $ws AND status IN ["todo", "in_progress"] ORDER BY created_at DESC LIMIT 30;`,
772→        { ws: auth.workspaceRecord },
773→      ).then((r) => r[0] ?? []),
774→    ]);
775→
776→    // Truncate diff for token budget
777→    const truncatedDiff = body.diff.length > 8000 ? body.diff.slice(0, 8000) + "\n... (truncated)" : body.diff;
778→
779→    const result = await generateObject({
780→      model: extractionModel,
781→      schema: commitCheckSchema,
782→      temperature: 0.1,
783→      system: [
784→        "You are a pre-commit analyzer for a knowledge graph-integrated development workflow.",
785→        "Analyze the staged git diff and commit message against the project context.",
786→        "Detect:",
787→        "1. Task completions — does this commit complete or substantially finish any active tasks?",
788→        "2. Unlogged decisions — does this commit introduce architectural or design decisions not already in the knowledge graph?",
789→        "3. Constraint violations — does this commit contradict any confirmed decisions or active constraints?",
790→        "Be conservative: only flag items with genuine evidence in the diff. Empty arrays are fine if nothing is detected.",
791→      ].join("\n"),
792→      prompt: [
793→        "## Commit message",
794→        body.commit_message || "(no message)",
795→        "",
796→        "## Staged diff",
797→        truncatedDiff,
798→        "",
799→        "## Active tasks",
800→        activeTasks.length > 0
801→          ? activeTasks.map((t) => `- [${t.status}] ${t.title}`).join("\n")
802→          : "(no active tasks)",
803→        "",
804→        "## Recent decisions",
805→        (() => {
806→          const allDecisions = [...decisions.confirmed, ...decisions.provisional, ...decisions.contested];
807→          return allDecisions.length > 0
808→            ? allDecisions.map((d) => `- [${d.status}] ${d.summary}`).join("\n")
809→            : "(no decisions)";
810→        })(),
811→        "",
812→        "## Active constraints",
813→        constraints.length > 0
814→          ? constraints.map((c) => `- [${c.severity}] ${c.text}`).join("\n")
815→          : "(no constraints)",
816→      ].join("\n"),
817→    });
818→
819→    return jsonResponse(result.object, 200);
820→  }
