  7→
  8→  constructor(config: BrainConfig) {
  9→    this.baseUrl = config.server_url.replace(/\/$/, "");
 10→    this.workspaceId = config.workspace;
 11→    this.apiKey = config.api_key;
 12→  }
 13→
 14→  private headers(): Record<string, string> {
 15→    return {
 16→      "Content-Type": "application/json",
 17→      Authorization: `Bearer ${this.apiKey}`,
 18→    };
 19→  }
