327→/** Load entities changed since a timestamp for the recent_changes field */
328→async function loadRecentChanges(
329→  surreal: Surreal,
330→  workspaceRecord: RecordId<"workspace", string>,
331→  projectRecord: RecordId<"project", string>,
332→  since: string,
333→): Promise<RecentChangeContext[]> {
334→  const sinceDate = new Date(since);
335→
336→  const query = `
337→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
338→
339→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
340→    FROM decision
341→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
342→    ORDER BY updated_at DESC LIMIT 20;
343→
344→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
345→    FROM task
346→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
347→    ORDER BY updated_at DESC LIMIT 20;
348→
349→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
350→    FROM question
351→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
352→    ORDER BY updated_at DESC LIMIT 20;
353→
354→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
355→  `;
356→
357→  const results = await surreal
358→    .query<[null, null, null, null, RecentChangeRow[]]>(query, {
359→      project: projectRecord,
360→      workspace: workspaceRecord,
361→      since: sinceDate,
362→    })
363→    .collect<[null, null, null, null, RecentChangeRow[]]>();
364→
365→  const rows = results[4] ?? [];
366→
367→  return rows.map((r) => ({
368→    entity_type: r.entity_type,
369→    entity_name: r.entity_name,
370→    change_type: r.change_type,
371→    changed_at: toIso(r.changed_at),
372→  }));
373→}
374→
375→type RecentChangeRow = {
376→  entity_type: string;
377→  entity_name: string;
378→  change_type: string;
379→  changed_at: Date | string;
380→};
