 1→import { RecordId, type Surreal } from "surrealdb";
 2→import { verifyApiKey } from "./api-key";
 3→import { jsonError } from "../http/response";
 4→
 5→type WorkspaceRow = {
 6→  id: RecordId<"workspace", string>;
 7→  name: string;
 8→  api_key_hash?: string;
 9→};
10→
11→export type McpAuthResult = {
12→  workspaceRecord: RecordId<"workspace", string>;
13→  workspaceName: string;
14→};
15→
16→/**
17→ * Authenticate an MCP request via Bearer token.
18→ * Checks the Authorization header against workspace API key hashes.
19→ * Returns workspace context on success, or an error Response.
20→ */
21→export async function authenticateMcpRequest(
22→  request: Request,
23→  workspaceId: string,
24→  surreal: Surreal,
25→): Promise<McpAuthResult | Response> {
26→  const authHeader = request.headers.get("authorization");
27→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
28→    return jsonError("missing or invalid Authorization header", 401);
29→  }
30→
31→  const apiKey = authHeader.slice(7);
32→  if (!apiKey) {
33→    return jsonError("empty API key", 401);
34→  }
35→
36→  const workspaceRecord = new RecordId("workspace", workspaceId);
37→  const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
38→  if (!workspace) {
39→    return jsonError("workspace not found", 404);
40→  }
41→
42→  if (!workspace.api_key_hash) {
43→    return jsonError("workspace has no API key configured — run brain init", 403);
44→  }
45→
46→  const valid = await verifyApiKey(apiKey, workspace.api_key_hash);
47→  if (!valid) {
48→    return jsonError("invalid API key", 401);
49→  }
50→
51→  return {
52→    workspaceRecord,
53→    workspaceName: workspace.name,
54→  };
55→}
