    } else if (d.status === "confirmed") {
      confirmed.push(ctx);
    }
  }

  // Map tasks
  const activeTasks: TaskContext[] = taskRows
    .filter((t) => t.status !== "done" && t.status !== "completed")
    .map((t) => ({
      id: toId(t.id),
      title: t.title,
      status: t.status,
      ...(t.priority ? { priority: t.priority } : {}),
